def _compute_file_hash(filepath: str) -> str:
    """Compute SHA256 hash of file content for change detection."""
    h = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            h.update(chunk)
    return h.hexdigest()

